import{_ as o,o as i,c as a,ae as l}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"故障排查","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/troubleshooting.md","filePath":"zh-CN/troubleshooting.md","lastUpdated":1777540909000}'),d={name:"zh-CN/troubleshooting.md"};function r(t,e,c,s,n,p){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h1><h2 id="_401-unauthorized" tabindex="-1"><code>401 Unauthorized</code> <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;`401 Unauthorized`&quot;">​</a></h2><p>检查：</p><ul><li>是否带上了 <code>Authorization</code> 请求头</li><li>是否使用了 <code>Bearer &lt;token&gt;</code> 格式</li><li><code>/v1/*</code> 是否使用的是 external API key</li><li>是否误把 Admin Key 当成客户端 token；Admin Key 只用于 <code>/admin/*</code></li><li>该 key 是否已经被吊销</li></ul><h2 id="本机内嵌语音模型未激活" tabindex="-1">本机内嵌语音模型未激活 <a class="header-anchor" href="#本机内嵌语音模型未激活" aria-label="Permalink to &quot;本机内嵌语音模型未激活&quot;">​</a></h2><p>如果桌面录音或 <code>/v1/audio/transcriptions</code> 在转录前就失败，请检查：</p><ul><li>打开 <strong>设置 -&gt; Local speech models</strong></li><li>下载一个内置模型，例如 <code>Whisper Base</code>、<code>Whisper Small</code> 或 <code>SenseVoice</code>，或手动放入兼容的 Whisper.cpp <code>.bin</code> 模型</li><li>激活当前宿主要使用的模型</li></ul><p>这个排查只适用于桌面 App 内嵌的本地 VILab Server，且 <strong>设置 -&gt; Routing and models -&gt; STT mode</strong> 设为 <code>Local</code> 的情况。无头服务端的本地模型叫 <code>server-local</code>，表示服务端调用 SenseVoice worker，不是旧桌面单机 <code>Local</code>。</p><h2 id="设置改了但似乎没有生效" tabindex="-1">设置改了但似乎没有生效 <a class="header-anchor" href="#设置改了但似乎没有生效" aria-label="Permalink to &quot;设置改了但似乎没有生效&quot;">​</a></h2><p>现在设置会在每次调整后自动保存。</p><p>如果听写优先级、Provider 或路由切换后看起来没有生效，请检查：</p><ul><li>先等设置页底部状态从 <code>保存中...</code> 恢复</li><li>重新打开 <strong>设置</strong>，确认刚才修改的值仍然被选中</li><li>等自动保存完成后再重新尝试一次听写</li></ul><h2 id="已切到云端-stt-但转录仍然失败" tabindex="-1">已切到云端 STT 但转录仍然失败 <a class="header-anchor" href="#已切到云端-stt-但转录仍然失败" aria-label="Permalink to &quot;已切到云端 STT 但转录仍然失败&quot;">​</a></h2><p>请检查：</p><ul><li><strong>设置 -&gt; Routing and models -&gt; STT mode</strong> 已切到 <code>Cloud</code></li><li>已选择可用的云端 STT provider</li><li>该 provider profile 没有被禁用</li><li>该 provider 的 API key 已经配置</li><li>云端 STT model 名称与该 provider 匹配</li></ul><h2 id="测试平台里的-smart-clean-看起来没有变化" tabindex="-1">测试平台里的 <code>Smart Clean</code> 看起来没有变化 <a class="header-anchor" href="#测试平台里的-smart-clean-看起来没有变化" aria-label="Permalink to &quot;测试平台里的 `Smart Clean` 看起来没有变化&quot;">​</a></h2><p>这通常不是 bug。</p><p>Prompt Lab 里的 <code>Smart Clean</code> 只执行本地清洗规则，不会调用 Provider、模型、Preset 或 Prompt Override。若输入里没有明显的低风险口头语、重复词或改口，它就可能保持原文不变，同时显示类似 <code>本地规则 · &lt;1ms</code> 的耗时。</p><h2 id="测试平台里的-polished-提示-add-the-api-key-for-groq-in-settings-first" tabindex="-1">测试平台里的 <code>Polished</code> 提示 <code>Add the API key for groq in Settings first</code> <a class="header-anchor" href="#测试平台里的-polished-提示-add-the-api-key-for-groq-in-settings-first" aria-label="Permalink to &quot;测试平台里的 `Polished` 提示 `Add the API key for groq in Settings first`&quot;">​</a></h2><p>这表示云端请求在真正发出前就被拦住了，因为当前选中的文本变换 Provider 没有可用 API key。</p><p>请检查：</p><ul><li><strong>设置 -&gt; Provider profiles</strong> 里已经为对应 Provider 填好了 API key</li><li>该 provider profile 处于启用状态</li><li>所选模型对这个 Provider 是有效的</li></ul><p>然后重新打开测试平台或重新运行对比。</p><h2 id="polished-没有润色但仍然输出了文本" tabindex="-1"><code>Polished</code> 没有润色但仍然输出了文本 <a class="header-anchor" href="#polished-没有润色但仍然输出了文本" aria-label="Permalink to &quot;`Polished` 没有润色但仍然输出了文本&quot;">​</a></h2><p>这是预期的快速回退行为。VILab 会先生成 <code>Smart Clean</code>，再尝试调用文本变换 Provider 做 <code>Polished</code>。如果 Provider 超时、网络失败、模型没有返回文本，或输出触发语言漂移/高风险改写保护，最终会直接使用 <code>Smart Clean</code>，也就是保留原始转写内容并用本地规则去掉语气词、重复词和明显改口。</p><p>当前默认等待时间：</p><ul><li><code>Ollama</code> 后处理总超时：8 秒</li><li>云端后处理总超时：15 秒</li><li>后处理连接超时：2 秒</li><li>云端或远程 STT 总超时：45 秒</li><li>云端或远程 STT 连接超时：5 秒</li></ul><p>如果需要临时调整，可以设置这些环境变量，单位是毫秒：</p><ul><li><code>VILAB_OLLAMA_TRANSFORM_TIMEOUT_MS</code></li><li><code>VILAB_CLOUD_TRANSFORM_TIMEOUT_MS</code></li><li><code>VILAB_STT_REQUEST_TIMEOUT_MS</code></li></ul><h2 id="测试平台里的-prompt-override-像是没有生效" tabindex="-1">测试平台里的 Prompt Override 像是没有生效 <a class="header-anchor" href="#测试平台里的-prompt-override-像是没有生效" aria-label="Permalink to &quot;测试平台里的 Prompt Override 像是没有生效&quot;">​</a></h2><p>Prompt Override 只对 <code>Polished</code> 生效。</p><p>如果你把自定义 Prompt 填进 <code>Smart Clean</code> 列，它不会被使用，因为 V1 的 <code>Smart Clean</code> 被设计成纯本地规则链路。</p><h2 id="whisper-rs-sys-编译失败" tabindex="-1"><code>whisper-rs-sys</code> 编译失败 <a class="header-anchor" href="#whisper-rs-sys-编译失败" aria-label="Permalink to &quot;`whisper-rs-sys` 编译失败&quot;">​</a></h2><p>如果你在 Windows 上执行 <code>npm run dev</code> 或 <code>cargo check</code> 时卡在 <code>whisper-rs-sys</code>：</p><ul><li>先尝试 <code>npm run cargo:check</code>，它会优先自动探测常见的 Windows <code>libclang</code> 安装位置</li><li>确认机器上有可用的 64-bit <code>libclang.dll</code></li><li>把 <code>LIBCLANG_PATH</code> 指向该 DLL 所在目录</li><li>重新打开终端后再重试</li></ul><p>这属于本地 Whisper 运行时的构建前提，不是接口配置错误。</p><h2 id="windows-上的-onnx-runtime-或-sensevoice-启动失败" tabindex="-1">Windows 上的 ONNX Runtime 或 SenseVoice 启动失败 <a class="header-anchor" href="#windows-上的-onnx-runtime-或-sensevoice-启动失败" aria-label="Permalink to &quot;Windows 上的 ONNX Runtime 或 SenseVoice 启动失败&quot;">​</a></h2><p>如果桌面 App 在准备内置 SenseVoice 运行时时失败，请检查：</p><ul><li>尽量通过仓库脚本启动，例如 <code>npm run dev</code>、<code>npm run build</code>、<code>npm run cargo:check</code></li><li>不要直接在绕过 <code>scripts/with-libclang.mjs</code> 的 shell 里运行 <code>cargo</code></li><li>只有在脚本明确提示下载包损坏时，才删除残留的 ONNX Runtime 临时文件后重试</li></ul><p>仓库的启动脚本现在会自动下载并接入 Windows 所需的 ONNX Runtime 文件。</p><h2 id="macos-上全局快捷键没有触发" tabindex="-1">macOS 上全局快捷键没有触发 <a class="header-anchor" href="#macos-上全局快捷键没有触发" aria-label="Permalink to &quot;macOS 上全局快捷键没有触发&quot;">​</a></h2><p>请检查：</p><ul><li><strong>系统设置 -&gt; 隐私与安全性 -&gt; 辅助功能</strong> 中，已经允许你当前实际启动 VILab 的终端、Codex 宿主或打包后的 VILab.app</li><li>你当前运行的是已经包含 macOS 事件监听式快捷键后端的新版本</li><li>当前快捷键里至少包含 <code>Command</code> 或 <code>Control</code></li><li>当前组合没有撞上明显的系统保留快捷键，例如 <code>Cmd+Space</code> 或 <code>Cmd+Option+Space</code></li></ul><p>当前 macOS 默认快捷键是 <code>Cmd+Shift+Option+D</code>。</p><h2 id="macos-上录音结束后能转写-但动画看起来几乎没反应" tabindex="-1">macOS 上录音结束后能转写，但动画看起来几乎没反应 <a class="header-anchor" href="#macos-上录音结束后能转写-但动画看起来几乎没反应" aria-label="Permalink to &quot;macOS 上录音结束后能转写，但动画看起来几乎没反应&quot;">​</a></h2><p>如果最终仍然能输出转录文本，通常说明麦克风音频已经正常传入模型。</p><p>请检查：</p><ul><li>App 已获得麦克风权限</li><li>当前运行版本是 <code>0.1.6</code> 或更高版本，这个版本增强了 macOS 录音动画使用的电平映射</li><li>你测试的是最新一次 <code>npm run dev</code> 会话，或重新打包后的新 App</li></ul><p>这种现象通常是 UI 电平映射偏弱，不是转录链路本身失败。</p><h2 id="windows-release-启动后闪退" tabindex="-1">Windows Release 启动后闪退 <a class="header-anchor" href="#windows-release-启动后闪退" aria-label="Permalink to &quot;Windows Release 启动后闪退&quot;">​</a></h2><p>如果 Windows 的安装包点击后立刻退出，请按这个顺序提交问题：</p><ul><li>打开 <code>%APPDATA%\\\\com.vilab.desktop\\\\startup-trace.log</code></li><li>到 <a href="https://github.com/Ro-In-AI/VILab-public/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提一个 issue</li><li>把 <code>startup-trace.log</code> 附上去，同时说明 Windows 版本、安装包版本，以及是否在首次启动时出现该问题</li></ul><p>如果 <code>%APPDATA%\\\\com.vilab.desktop\\\\startup-trace.log</code> 没有生成或是空的，也请在 issue 里直接说明。</p><h2 id="服务不可达" tabindex="-1">服务不可达 <a class="header-anchor" href="#服务不可达" aria-label="Permalink to &quot;服务不可达&quot;">​</a></h2><p>检查：</p><ul><li>远程 VILab Server 或桌面 App 内嵌的本地 VILab Server 是否正在运行</li><li><strong>Server URL</strong> 是否配置正确</li><li>宿主机防火墙是否已放行服务端口</li><li>客户端调用的是否是可达的局域网 IP 或主机名</li></ul><h2 id="局域网或内嵌服务客户端无法连接" tabindex="-1">局域网或内嵌服务客户端无法连接 <a class="header-anchor" href="#局域网或内嵌服务客户端无法连接" aria-label="Permalink to &quot;局域网或内嵌服务客户端无法连接&quot;">​</a></h2><p>检查：</p><ul><li>服务是否仍然只绑定在 <code>127.0.0.1</code></li><li>客户端与宿主机是否在同一网络</li><li>安全软件是否拦截了服务端口</li></ul><h2 id="模型不支持" tabindex="-1">模型不支持 <a class="header-anchor" href="#模型不支持" aria-label="Permalink to &quot;模型不支持&quot;">​</a></h2><p><code>/v1/audio/transcriptions</code> 目前只接受：</p><ul><li><code>/health</code> 返回的当前公开 STT 模型别名</li></ul><p>如果传入其他 <code>model</code> 值，服务会返回 <code>400 Unsupported model</code>。</p><h2 id="音频格式不支持" tabindex="-1">音频格式不支持 <a class="header-anchor" href="#音频格式不支持" aria-label="Permalink to &quot;音频格式不支持&quot;">​</a></h2><p>当前公开 HTTP 转录接口只接受 WAV。</p><p>如果你传入其他容器或编码，请先转换成 WAV 再调用 <code>/v1/audio/transcriptions</code>。</p>',66)])])}const m=o(d,[["render",r]]);export{u as __pageData,m as default};
